## ✅ Parallelized Version Using `ThreadPoolExecutor` (I/O-bound)

```python
import os
import re
from collections import Counter
from concurrent.futures import ThreadPoolExecutor

def process_file(file_path):
    try:
        with open(file_path, 'r', encoding='utf-8') as file:
            text = file.read().lower()
            words = re.findall(r'\b[a-z]+\b', text)
            return Counter(words)
    except Exception as e:
        print(f"Error reading file {file_path}: {e}")
        return Counter()

def count_words_in_directory(directory):
    if not os.path.isdir(directory):
        print(f"Directory '{directory}' does not exist.")
        return Counter()

    file_paths = [
        os.path.join(directory, filename)
        for filename in os.listdir(directory)
        if os.path.isfile(os.path.join(directory, filename)) and filename.lower().endswith('.txt')
    ]

    # Use ThreadPoolExecutor for I/O-bound tasks
    with ThreadPoolExecutor() as executor:
        results = executor.map(process_file, file_paths)

    # Aggregate results
    total_counter = Counter()
    for result in results:
        total_counter.update(result)

    return total_counter.most_common(5)

if __name__ == "__main__":
    directory = input("Enter the directory path: ").strip()
    top_words = count_words_in_directory(directory)

    if top_words:
        print("\nTop 5 most frequent words:")
        for word, count in top_words:
            print(f"{word}: {count}")
    else:
        print("No text files found or no words counted.")
```

