Here's a **C++ program** that calculates the **nth number** in this sequence using **recursion**:

```cpp
#include <iostream>
using namespace std;

// Function to calculate the nth number in the modified Tribonacci sequence
int tribonacci(int n) {
    if (n == 0) return 0;
    if (n == 1 || n == 2) return -1;

    return tribonacci(n - 1) + tribonacci(n - 2) + tribonacci(n - 3);
}

int main() {
    int n;

    cout << "Enter the position of the Tribonacci number you want: ";
    cin >> n;

    if (n < 0) {
        cout << "Please enter a non-negative integer." << endl;
    } else {
        cout << "The " << n << "th Tribonacci number is: " << tribonacci(n) << endl;
    }

    return 0;
}
```

